    %3 = cuda_tile.mulf %0, %1 : !cuda_tile.tile<f32>
    %4 = cuda_tile.addf %3, %2 rounding<nearest_even> : !cuda_tile.tile<f32>

    return %4 : !cuda_tile.tile<f32>
  }
}

